head.b:skin:
/*------------------------------------------------------------
ULTRA GRADIENT COLOR VARIABLES & CORE ARCHITECTURE
------------------------------------------------------------*/
:root {
    --primary-gradient: linear-gradient(135deg, #ff007f 0%, #7928ca 100%);
    --secondary-gradient: linear-gradient(135deg, #00f2fe 0%, #4facfe 100%);
    --accent-glow: linear-gradient(90deg, #ff007f, #7928ca, #4facfe, #ff007f);
    --accent-color: #ff007f;
    --dark-bg: #090d16;
    --dark-card: #131c2e;
    --light-bg: #f4f6f9;
    --light-card: #ffffff;
    --text-main: #1e293b;
    --text-muted: #64748b;
    --font-premium: 'Plus Jakarta Sans', sans-serif;
    --radius-prm: 18px;
    --radius-sm: 10px;
    --shadow-prm: 0 15px 35px -5px rgba(121, 40, 202, 0.12);
    --transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);
}

/* System Dark Mode Override */
body.dark-mode {
    --light-bg: var(--dark-bg);
    --light-card: var(--dark-card);
    --text-main: #f8fafc;
    --text-muted: #94a3b8;
    --shadow-prm: 0 15px 40px -10px rgba(0, 0, 0, 0.6);
}

/* Core Reset CSS */
* { box-sizing: border-box; margin: 0; padding: 0; }
body { font-family: var(--font-premium); background-color: var(--light-bg); color: var(--text-main); transition: var(--transition); overflow-x: hidden; -webkit-font-smoothing: antialiased; }
a { color: inherit; text-decoration: none; transition: var(--transition); }
img { max-width: 100%; height: auto; display: block; border-radius: var(--radius-sm); }

/* Reading Progress Tracker */
#progress-bar { position: fixed; top: 0; left: 0; width: 0%; height: 5px; background: var(--primary-gradient); z-index: 99999; transition: width 0.1s ease; }

/* Layout Wrapper */
.container { max-width: 1280px; margin: 0 auto; padding: 0 24px; }

/* Flash News Ticker Layout */
.top-bar { background: #05070f; color: #fff; padding: 14px 0; font-size: 13px; font-weight: 500; border-bottom: 1px solid rgba(255,255,255,0.04); }
.ticker-wrap { display: flex; align-items: center; justify-content: space-between; gap: 20px; }
.ticker-box { display: flex; align-items: center; overflow: hidden; width: 75%; }
.ticker-title { background: var(--primary-gradient); padding: 6px 16px; font-weight: 800; border-radius: 8px; margin-right: 15px; white-space: nowrap; box-shadow: 0 4px 15px rgba(255, 0, 127, 0.35); font-size: 11px; letter-spacing: 1px; text-transform: uppercase; }
.ticker-content { display: inline-block; white-space: nowrap; animation: ticker 35s linear infinite; color: #cbd5e1; }
@keyframes ticker { 0% { transform: translate3d(100%, 0, 0); } 100% { transform: translate3d(-100%, 0, 0); } }

/* Sticky Glassmorphic Header Navigation */
header { background: rgba(255, 255, 255, 0.85); backdrop-filter: blur(15px); -webkit-backdrop-filter: blur(15px); position: sticky; top: 0; z-index: 9999; box-shadow: 0 4px 30px rgba(0,0,0,0.02); transition: var(--transition); border-bottom: 1px solid rgba(0,0,0,0.04); }
body.dark-mode header { background: rgba(19, 28, 46, 0.85); border-bottom: 1px solid rgba(255,255,255,0.05); }
.header-inner { display: flex; justify-content: space-between; align-items: center; padding: 16px 0; }

/* Brand Identity Logo Style */
.logo h1 { font-size: 28px; font-weight: 800; background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; letter-spacing: -0.5px; position: relative; }

/* Professional Mega Navigation System */
nav ul { display: flex; list-style: none; gap: 32px; }
nav ul li a { font-weight: 600; font-size: 15px; color: var(--text-main); position: relative; padding: 8px 0; display: flex; align-items: center; gap: 6px; }
nav ul li a::after { content: ''; position: absolute; bottom: 0; left: 0; width: 0; height: 3px; background: var(--primary-gradient); border-radius: 2px; transition: var(--transition); }
nav ul li a:hover::after { width: 100%; }

/* Floating Control Buttons */
.nav-actions { display: flex; align-items: center; gap: 15px; }
.action-btn { width: 44px; height: 44px; border-radius: 50%; background: var(--light-bg); display: flex; align-items: center; justify-content: center; cursor: pointer; transition: var(--transition); border: 1px solid rgba(0,0,0,0.04); color: var(--text-main); }
.action-btn:hover { transform: scale(1.08) rotate(15deg); background: var(--primary-gradient); color: #fff; box-shadow: 0 8px 20px rgba(121, 40, 202, 0.2); }

/* Live Search Popup Overlay */
.search-overlay { position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: rgba(5, 7, 15, 0.95); z-index: 99999; display: none; align-items: center; justify-content: center; backdrop-filter: blur(10px); }
.search-dialog { background: var(--light-card); padding: 40px; border-radius: var(--radius-prm); width: 92%; max-width: 600px; box-shadow: var(--shadow-prm); border: 1px solid rgba(255,255,255,0.08); position: relative; }
.search-dialog input { width: 100%; padding: 18px; border: 2px solid rgba(0,0,0,0.05); border-radius: 12px; background: var(--light-bg); color: var(--text-main); font-size: 16px; font-family: var(--font-premium); font-weight: 600; outline: none; transition: var(--transition); }
.search-dialog input:focus { border-color: var(--accent-color); box-shadow: 0 0 15px rgba(255,0,127,0.15); }

/* Ultra Modern Hero Layout Carousel Space */
.hero-banner { background: var(--primary-gradient); padding: 60px 40px; color: #fff; border-radius: var(--radius-prm); margin-top: 35px; text-align: center; box-shadow: 0 20px 45px rgba(121, 40, 202, 0.25); position: relative; overflow: hidden; }
.hero-banner h2 { font-size: 36px; font-weight: 800; margin-bottom: 12px; letter-spacing: -0.5px; }
.hero-banner p { font-size: 16px; opacity: 0.95; font-weight: 500; }
.hero-banner::before { content: ''; position: absolute; top: -50%; left: -50%; width: 200%; height: 200%; background: radial-gradient(circle, rgba(255,255,255,0.1) 0%, transparent 60%); pointer-events: none; }

/* Grid Architecture Systems */
.main-wrapper { display: grid; grid-template-columns: 1fr; gap: 40px; margin-top: 45px; }
@media(min-width: 992px) { .main-wrapper { grid-template-columns: 2.3fr 1fr; } }

/* Homepage Posts Grid Style */
.posts-grid { display: grid; grid-template-columns: 1fr; gap: 30px; }
@media(min-width: 650px) { .posts-grid { grid-template-columns: 1fr 1fr; } }

.card { background: var(--light-card); border-radius: var(--radius-prm); overflow: hidden; box-shadow: var(--shadow-prm); transition: var(--transition); border: 1px solid rgba(0,0,0,0.02); display: flex; flex-direction: column; height: 100%; }
.card:hover { transform: translateY(-10px); box-shadow: 0 25px 50px -10px rgba(121, 40, 202, 0.22); }
.card-thumb { height: 240px; background: #e2e8f0; position: relative; overflow: hidden; }
.card-thumb img { width: 100%; height: 100%; object-fit: cover; transition: var(--transition); }
.card:hover .card-thumb img { transform: scale(1.08); }

.badge { position: absolute; top: 18px; left: 18px; background: var(--secondary-gradient); color: #fff; padding: 6px 14px; font-size: 11px; font-weight: 700; border-radius: 8px; text-transform: uppercase; box-shadow: 0 6px 15px rgba(79, 172, 254, 0.35); }
.card-content { padding: 28px; flex-grow: 1; display: flex; flex-direction: column; justify-content: space-between; }
.card-meta { font-size: 12px; color: var(--text-muted); margin-bottom: 14px; display: flex; gap: 16px; font-weight: 600; }
.card-meta i { color: var(--accent-color); }
.card-title { font-size: 22px; font-weight: 700; line-height: 1.4; margin-bottom: 12px; color: var(--text-main); }
.card-text { font-size: 14px; color: var(--text-muted); margin-bottom: 24px; line-height: 1.6; }
.read-btn { display: inline-flex; align-items: center; gap: 8px; font-weight: 700; font-size: 14px; background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; width: fit-content; }
.read-btn i { transition: var(--transition); color: var(--accent-color); -webkit-text-fill-color: initial; }
.card:hover .read-btn i { transform: translateX(6px); }

/* ------------------------------------------------------------
ADVANCED INNER POST CONTENT PAGE STYLING (The Fix)
------------------------------------------------------------*/
.post-body-container { background: var(--light-card); padding: 40px; border-radius: var(--radius-prm); box-shadow: var(--shadow-prm); border: 1px solid rgba(0,0,0,0.02); }
.post-main-title { font-size: 34px; font-weight: 800; line-height: 1.3; margin-bottom: 20px; color: var(--text-main); }
.breadcrumb { display: flex; gap: 8px; font-size: 13px; color: var(--text-muted); margin-bottom: 25px; font-weight: 600; }
.breadcrumb a:hover { color: var(--accent-color); }

/* Table Of Contents UI */
.table-of-contents { background: var(--light-bg); border-left: 5px solid var(--accent-color); padding: 20px; border-radius: var(--radius-sm); margin: 30px 0; }
.toc-title { font-weight: 800; font-size: 16px; text-transform: uppercase; margin-bottom: 12px; display: flex; align-items: center; gap: 10px; }
.toc-list { list-style: none; padding-left: 5px; }
.toc-list li { margin-bottom: 8px; font-size: 14px; font-weight: 600; }

/* Typography inside posts */
.post-content-area { font-size: 16px; line-height: 1.8; color: var(--text-main); }
.post-content-area h2, .post-content-area h3 { margin: 35px 0 15px; font-weight: 800; color: var(--text-main); }
.post-content-area h2 { font-size: 26px; border-bottom: 2px solid rgba(0,0,0,0.05); padding-bottom: 8px; }
.post-content-area p { margin-bottom: 20px; }

/* Dynamic Code Block Component & Copy Button */
pre { background: #0f172a; color: #f8fafc; padding: 20px; border-radius: var(--radius-sm); overflow-x: auto; position: relative; margin: 30px 0; font-family: monospace; }
.copy-btn { position: absolute; top: 12px; right: 12px; background: var(--primary-gradient); border: none; color: white; padding: 5px 12px; font-size: 11px; font-weight: 700; border-radius: 6px; cursor: pointer; box-shadow: 0 4px 10px rgba(0,0,0,0.3); }

/* Premium Author Details Widget Box */
.author-box { display: flex; gap: 20px; align-items: center; background: var(--light-bg); padding: 25px; border-radius: var(--radius-sm); margin-top: 50px; border: 1px solid rgba(0,0,0,0.03); }
.author-avatar { width: 70px; height: 70px; border-radius: 50%; object-fit: cover; border: 3px solid var(--accent-color); }
.author-info h4 { font-size: 18px; font-weight: 800; margin-bottom: 5px; }
.author-info p { font-size: 13px; color: var(--text-muted); font-weight: 500; }

/* Custom Advanced Comment System area */
.comment-area-box { margin-top: 50px; background: var(--light-card); padding: 35px; border-radius: var(--radius-prm); box-shadow: var(--shadow-prm); }
.comment-title { font-size: 20px; font-weight: 800; margin-bottom: 25px; text-transform: uppercase; }

/* Professional Sidebar Modules */
.sidebar { display: flex; flex-direction: column; gap: 35px; }
.widget { background: var(--light-card); padding: 30px; border-radius: var(--radius-prm); box-shadow: var(--shadow-prm); border: 1px solid rgba(0,0,0,0.02); }
.widget-title { font-size: 16px; font-weight: 800; text-transform: uppercase; margin-bottom: 22px; position: relative; padding-bottom: 12px; letter-spacing: 0.5px; }
.widget-title::after { content: ''; position: absolute; bottom: 0; left: 0; width: 45px; height: 4px; background: var(--primary-gradient); border-radius: 2px; }

/* Heavy Premium Footer Columns Layout */
footer { background: #05070f; color: #94a3b8; padding: 80px 0 35px; margin-top: 90px; border-top: 3px solid rgba(121, 40, 202, 0.25); }
.footer-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); gap: 45px; margin-bottom: 50px; }
.footer-col h3 { color: #fff; margin-bottom: 25px; font-size: 20px; font-weight: 800; position: relative; }
.footer-col h3::after { content: ''; position: absolute; bottom: -8px; left: 0; width: 35px; height: 3px; background: var(--secondary-gradient); }
.footer-col p { font-size: 14px; line-height: 1.8; color: #94a3b8; }
.footer-links { list-style: none; }
.footer-links li { margin-bottom: 12px; font-size: 14px; font-weight: 600; }
.footer-links li a:hover { color: #fff; padding-left: 5px; }

/* 100% Secure Private Copyright Brand Stamp */
.footer-bottom { border-top: 1px solid rgba(255,255,255,0.06); padding-top: 30px; text-align: center; font-size: 14px; font-weight: 600; color: #475569; }
.footer-bottom a { background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; font-weight: 800; }

/* UI Navigation Operations Button */
#back-to-top { position: fixed; bottom: 35px; right: 35px; background: var(--primary-gradient); color: #fff; width: 48px; height: 48px; border-radius: 50%; display: none; align-items: center; justify-content: center; cursor: pointer; z-index: 9999; box-shadow: 0 10px 25px rgba(255, 0, 127, 0.4); border: none; transition: var(--transition); }
#back-to-top:hover { transform: translateY(-6px); }

body.script:
//
// 1. Dark Mode State Management Mechanics
const darkToggle = document.getElementById('dark-mode-toggle');
const icon = darkToggle.querySelector('i');
darkToggle.addEventListener('click', () => {
    document.body.classList.toggle('dark-mode');
    if(document.body.classList.contains('dark-mode')) {
        icon.className = 'fas fa-sun';
    } else {
        icon.className = 'fas fa-moon';
    }
});

// 2. Search Popup overlay toggle mechanism Control
const searchTrigger = document.getElementById('search-trigger');
const searchLayer = document.getElementById('search-layer');
searchTrigger.addEventListener('click', () => {
    searchLayer.style.display = (searchLayer.style.display === 'flex') ? 'none' : 'flex';
});
window.addEventListener('click', (e) => {
    if(e.target === searchLayer) searchLayer.style.display = 'none';
});

// 3. Document Reading Tracker & Dynamic Back to Top UI Display Loop
window.addEventListener('scroll', () => {
    const winScroll = document.body.scrollTop || document.documentElement.scrollTop;
    const height = document.documentElement.scrollHeight - document.documentElement.clientHeight;
    const scrolled = (winScroll / height) * 100;
    document.getElementById('progress-bar').style.width = scrolled + '%';

    const btt = document.getElementById('back-to-top');
    if(winScroll > 450) { btt.style.display = 'flex'; } else { btt.style.display = 'none'; }
});

document.getElementById('back-to-top').addEventListener('click', () => {
    window.scrollTo({top: 0, behavior: 'smooth'});
});

// 4. Live Automatic Timestamp Calendar Configuration Engine
document.getElementById('live-date').innerText = new Date().toLocaleDateString('en-US', { weekday: 'short', year: 'numeric', month: 'short', day: 'numeric' });

// 5. Code Injector Box Clipboard Facility System 
document.querySelectorAll('pre').forEach((block) => {
    const button = document.createElement('button');
    button.className = 'copy-btn';
    button.innerText = 'COPY';
    block.appendChild(button);
    button.addEventListener('click', () => {
        const text = block.innerText.replace('COPY', '');
        navigator.clipboard.writeText(text).then(() => {
            button.innerText = 'COPIED!';
            setTimeout(() => { button.innerText = 'COPY'; }, 2000);
        });
    });
});
//
